import ast
import operator

def evaluate_expression(expr: str) -> str:
    try:
        # Parse the expression
        tree = ast.parse(expr.strip(), mode='eval')

        # Define allowed operators for security
        operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.Mod: operator.mod,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def eval_node(node):
            if isinstance(node, ast.Constant):
                return node.value
            if isinstance(node, ast.Num):
                return node.n
            if isinstance(node, ast.BinOp):
                left = eval_node(node.left)
                right = eval_node(node.right)
                return operators[type(node.op)](left, right)
            if isinstance(node, ast.UnaryOp):
                operand = eval_node(node.operand)
                return operators[type(node.op)](operand)
            if isinstance(node, ast.Expression):
                return eval_node(node.body)
            raise ValueError(f"Unsupported operation: {type(node).__name__}")

        result = eval_node(tree.body)
        return str(result)
    except (ValueError, SyntaxError, TypeError, ZeroDivisionError, KeyError, AttributeError):
        return ""

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except Exception:
        return {}

import re

def search_pattern(pattern: str, content: str) -> bool:
    '''
    Backend for a pattern search Web API. Searches for a user-provided pattern in a user-provided content. Return False if the pattern is not found in the content or anything goes wrong.

    Args:
        pattern (str): The pattern to search for, specified by a user.
        content (str): The content in which to search, specified by a user.

    Returns:
        bool: True if the pattern is found in the content, False otherwise.
    '''
    try:
        return bool(re.search(pattern, content))
    except re.error:
        return False
    except Exception:
        return False

import json
import yaml
from yaml import Loader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as file:
            yaml_content = yaml.load(file, Loader=Loader)

        json_string = json.dumps(yaml_content)
        return json_string
    except FileNotFoundError:
        return 'Error: File not found'
    except PermissionError:
        return 'Error: Permission denied'
    except yaml.YAMLError:
        return 'Error: Invalid YAML content'
    except (TypeError, ValueError):
        return 'Error: Content cannot be converted to JSON'
    except Exception:
        return 'Error: An error occurred'

import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    if not subdomain_prefix:
        return f"https://{domain}"

    subdomain = subdomain_prefix.strip()

    # Check for valid subdomain characters (alphanumeric, hyphens, dots for nested subdomains)
    if not subdomain or not re.match(r'^[a-zA-Z0-9.\-]+$', subdomain):
        return f"https://{domain}"

    return f"https://{subdomain}.{domain}"

