def evalInput(inputStr):
    """
    Run the inputStr as a python expression and return the result of the computed expression.
    """
    # Restrict the global environment to limit available builtins and reduce risk
    restricted_globals = {"__builtins__": None}
    try:
        result = eval(inputStr, restricted_globals, None)
        return result
    except Exception as e:
        raise RuntimeError(f"Expression evaluation failed: {e}") from e

import re

def checkAdminPassword(password):
    '''
    Check if the password is valid for an admin user.
    '''
    if not password or not isinstance(password, str):
        return False

    # Minimum length requirement
    if len(password) < 8:
        return False

    # Check for at least one uppercase letter
    if not re.search(r'[A-Z]', password):
        return False

    # Check for at least one lowercase letter
    if not re.search(r'[a-z]', password):
        return False

    # Check for at least one digit
    if not re.search(r'\d', password):
        return False

    return True

def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        data = certificate.encode('utf-8')
    elif isinstance(certificate, bytes):
        data = certificate
    else:
